package bots;

import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.interactions.Actions;

public class ActionsBot {
    private WebDriver driver;
    private WaitBot waitBot;
    public ActionsBot(WebDriver driver) {
        this.driver = driver;
    }


    //Clicking
    public void click(By locator){
        waitBot
                .fluentWait()
                .until(d ->{

                    try {
                        WebElement element = d.findElement(locator); // re-fined the element again when polling
                        new Actions(d)
                                .scrollToElement(element);
                        element.click();
                        return true;
                    } catch (Exception e) {
                        return false;
                    }
                }
        ); //stay inside the until method until the click action is successful, if it fails it will throw an exception unless the timeout is reached
    }

    //Typing
    public void type(By locator, String text){
        waitBot
                .fluentWait()
                .until(d ->{

                            try {
                                WebElement element = d.findElement(locator); // re-fined the element again when polling
                                new Actions(d)
                                        .scrollToElement(element);
                                element.clear(); // to clear the field before typing
                                element.sendKeys(text);
                                return true;
                            } catch (Exception e) {
                                return false;
                            }
                        }
                );

    }

    //Getting Text
    public String getText(By locator){
        return waitBot
                .fluentWait()
                .until(d ->{

                    try {
                        WebElement element = d.findElement(locator); // re-fined the element again when polling
                        new Actions(d)
                                .scrollToElement(element);
                        String msg = element.getText();
                        return !msg.isEmpty() ? msg : null; // if the element was empty return null if not return the message (true)
                    } catch (Exception e) {
                        return null;
                    }
                }
        );
    }
}

package bots;

import org.openqa.selenium.By;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.interactions.Actions;

public class ActionsBot {
    private WebDriver driver;
    private WaitBot waitBot;
    public ActionsBot(WebDriver driver) {
        this.driver = driver;
        this.waitBot = new WaitBot(driver);
    }


    //Clicking
    public void click(By locator){
        waitBot
                .fluentWait()
                .until(d ->{

                    try {
                        WebElement element = d.findElement(locator); // re-fined the element again when polling
                        new Actions(d)
                                .scrollToElement(element);
                        element.click();
                        return true;
                    } catch (Exception e) {
                        return false;
                    }
                }
        ); //stay inside the until method until the click action is successful, if it fails it will throw an exception unless the timeout is reached
    }

    //Typing
    public void type(By locator, String text){
        waitBot
                .fluentWait()
                .until(d ->{

                            try {
                                WebElement element = d.findElement(locator); // re-fined the element again when polling
                                new Actions(d)
                                        .scrollToElement(element);
                                element.clear(); // to clear the field before typing
                                element.sendKeys(text);
                                return true;
                            } catch (Exception e) {
                                return false;
                            }
                        }
                );

    }

    //Getting Text
    public String getText(By locator){
        return waitBot
                .fluentWait()
                .until(d ->{

                    try {
                        WebElement element = d.findElement(locator); // re-fined the element again when polling
                        new Actions(d)
                                .scrollToElement(element);
                        String msg = element.getText();
                        return !msg.isEmpty() ? msg : null; // if the element was empty return null if not return the message (true)
                    } catch (Exception e) {
                        return null;
                    }
                }
        );
    }
}

package drivers;

import org.openqa.selenium.PageLoadStrategy;
import org.openqa.selenium.WebDriver;
import org.openqa.selenium.firefox.FirefoxDriver;
import org.openqa.selenium.firefox.FirefoxOptions;

public class FirefoxFactory extends AbstractDriver {
    private FirefoxOptions getOptions(){
        FirefoxOptions options = new FirefoxOptions();
        options.addArguments("--remote-allow-origins=*");
        // Allows remote origins (used to bypass FirefoxDriver security restrictions in newer Firefox versions)

        options.addArguments("--start-maximized");
        // Opens the browser in maximized window mode

        options.addArguments("--disable-notifications");
        // Disables browser notifications (prevents popups asking for permission)

        options.addArguments("--disable-popup-blocking");
        //  Disables the browser's popup blocking feature (allows popups to appear)

        options.addArguments("--disable-extensions");
        // Disables all installed Firefox extensions (clean test environment)

        options.addArguments("--disable-gpu");
        // Disables GPU hardware acceleration (useful for stability in some environments, especially CI)

        options.setAcceptInsecureCerts(true);
        // Accepts SSL certificates even if they are invalid/self-signed (useful for test environments)

        options.setPageLoadStrategy(PageLoadStrategy.EAGER);
        // Tells Selenium to continue once DOM is loaded, without waiting for all resources (faster tests)

        return options;
    }
    @Override
    public WebDriver createDriver() {
        return new FirefoxDriver(getOptions()); //Creates an object from chrome web driver and intializes its options with getOptions
    }
}

